import React from "react";
import useSplitPaymentStore from "../useSplitPaymentStore";
import useCalculateSchedule from "../hooks/useCalculateSchedule";

export function PlanScheduleItem({ item }) {
    if (item) {
        const { dueDate, dueAmt } = item
        return (<div className="m-2 bg-sky-50 p-4 w-2/3 grid gap-4 grid-cols-2 margin-auto">
            <div className="w-50">{'Rs.' + dueAmt}</div>
            <div className="w-50">{dueDdueDateLabelate}</div>
        </div>)
    }
}

function PlanSchedule() {
    const { activePlan, totalAmount, showInstallments } = useSplitPaymentStore((s) => s)
    const plansSchedule = useCalculateSchedule(activePlan, totalAmount)
    if (plansSchedule && plansSchedule.length > 0 && showInstallments) {
        console.log('dueDate', plansSchedule)

        return (
            <div className="flex flex-col justify-between items-center">
                {plansSchedule.map((item) => {
                    return (<PlanScheduleItem key={item.id} item={item} />)
                })}
            </div>
        )
    }
}

export default PlanSchedule
